import React, { useEffect, useState, useRef } from 'react';
import './Home.css';

// ─────────────────────────────────────────────────────────────────────────────
// 📸 SWAP PLACEHOLDERS FOR REAL IMAGES LATER
//
// When you're ready to add images:
//  1. Create the folder:  src/assets/images/
//  2. Add your image files there
//  3. Replace each <Placeholder> below with:
//       <img src={yourImport} alt="description" className="the-photo-class" />
//  4. Add the matching import at the top of this file
//
// Image slots & recommended sizes:
//  slide-1.jpg / slide-2.jpg / slide-3.jpg  →  hero bg overlay  (1400×700px)
//  hero-feature.jpg                          →  hero right panel (600×700px)
//  story.jpg                                 →  story section    (700×450px)
//  menu-korean-feast.jpg  etc.               →  menu cards       (600×600px)
//  dish-dragon-wing.jpg   etc.               →  dish cards       (500×400px)
//  gallery-1.jpg … gallery-6.jpg            →  gallery grid     (any, portrait for 1 & 4)
// ─────────────────────────────────────────────────────────────────────────────

// ─── DATA ─────────────────────────────────────────────────────────────────────

const SLIDES = [
  {
    id: 1,
    tag: 'Limited Time Offer',
    headline: ['5 + 1', 'MEALS'],
    sub: 'Save as much as 20% — the more you share, the more you save.',
    savings: 'Save as much as ₱298',
    bg: 'linear-gradient(120deg, #c8102e 0%, #8b0000 100%)',
  },
  {
    id: 2,
    tag: 'Signature Series',
    headline: ['HANDCRAFTED', 'FLAVOR'],
    sub: 'Every piece hand-brushed twice with our legendary Korean sauce.',
    savings: 'Now available for delivery',
    bg: 'linear-gradient(120deg, #0d0d0d 0%, #1a0005 100%)',
  },
  {
    id: 3,
    tag: 'Fan Favorite',
    headline: ['BOLD.', 'CRISPY.'],
    sub: 'Double-fried perfection — light, crunchy, impossibly good.',
    savings: 'Order online today',
    bg: 'linear-gradient(120deg, #6b0010 0%, #c8102e 100%)',
  },
];

const STATS = [
  { value: '150+', label: 'Menu Items' },
  { value: '25K+', label: 'Happy Guests' },
  { value: '12',   label: 'Years of Flavor' },
  { value: '4.9★', label: 'Rating' },
];

const CATEGORIES = [
  { name: 'Korean Feast',           count: '4 Menu', emoji: '🍗' },
  { name: 'Chicken & Seafood Rack', count: '2 Menu', emoji: '🦐' },
  { name: 'BonChon-to-Share',       count: '5 Menu', emoji: '📦' },
  { name: 'Rice Bowls',             count: '6 Menu', emoji: '🍚' },
];

const FEATURES = [
  { icon: '🔥', title: 'Fiery Flavors',  desc: 'Every dish crafted to ignite your taste buds with authentic spice blends sourced from around the globe.' },
  { icon: '🌿', title: 'Farm Fresh',      desc: 'We partner with local farmers to bring only the freshest, highest-quality ingredients to your plate.' },
  { icon: '👨‍🍳', title: 'Master Chefs', desc: 'Our culinary team brings decades of experience to every dish, combining tradition with innovation.' },
  { icon: '🚀', title: 'Fast Delivery',   desc: 'Hot, fresh, and delivered to your door in under 45 minutes — taste without the wait.' },
];

const DISHES = [
  { name: 'Dragon Wing Platter',   price: '₱449', tag: 'Best Seller', heat: 3 },
  { name: 'Smoky BBQ Ribs',        price: '₱699', tag: "Chef's Pick",  heat: 2 },
  { name: 'Inferno Burger',        price: '₱389', tag: 'New',          heat: 4 },
  { name: 'Garlic Parmesan Pasta', price: '₱349', tag: 'Crowd Fave',   heat: 1 },
];

